external_knowledge:
; Hurricane is a type of storm; 
; Temporary housing (accommodation) is required during evacuation; 
; The resident's identity is needed to track their evacuation history and storm experiences; 
; The average accommodation cost indicates the financial burden of evacuation; 
; The average wind speed represents the severity of the storm conditions faced by the residents.

sql:
SELECT AVG(evac_time) AS average_evacuation_time
FROM evacuation_decisions
WHERE transportation_used = 2;

SELECT resident_id, age
FROM residents
ORDER BY age DESC;

SELECT AVG(evacuation_expense) AS avg_evacuation_expense
FROM evacuation_history
WHERE previous_storm_experience = 1;
